queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?diplomas a :Diplomas .
    ?diplomas p:Title ?title .
    ?diplomas p:CompletionRequirements ?completionrequirements_f .
    FILTER(STR(?completionrequirements_f) = "Passing Exam")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?certificates a :Certificates .
    ?certificates p:Title ?title .
    ?certificates p:CompletionRequirements ?completionrequirements_f .
    FILTER(STR(?completionrequirements_f) = "Passing Exam")
    BIND(?title AS ?o0)
  }
}

